#!/usr/bin/env bash
# Example: AdaBeam on the ATAC start sequence (BPNet oracle).
#
# Run from the repo root:
#   bash examples/adabeam_atac.sh
#
python -m gradabeam \
    --optimizer adabeam \
    --oracle_script oracles/bpnet.py \
        --protein ATAC \
    --beam_size 2 \
    --n_rollouts_per_root 4 \
    --mutations_per_sequence 2.6667 \
    --rng_seed 0 \
    --debug True \
    --time_budget 60 \
    --start_sequence 
    
